"""Главный агент: цикл tool calling до final_answer."""

from __future__ import annotations

import json
import sys
from dataclasses import dataclass, field
from typing import Any

from .config import Settings
from .db import OracleClient
from .llm import LLMClient
from .prompts import build_system_prompt
from .tools import TOOL_SCHEMAS, ToolContext, call_tool


# Жёсткий потолок шагов — защита от зацикливания на локальной модели.
MAX_TURNS = 12

# Лимит на размер tool_result, который мы отдаём модели обратно (символы).
TOOL_RESULT_HARD_LIMIT = 16000


@dataclass
class AgentResult:
    answer: str
    supporting_data: dict[str, Any] = field(default_factory=dict)
    turns: int = 0
    tool_calls: list[dict[str, Any]] = field(default_factory=list)
    completed: bool = True
    error: str | None = None


def _truncate(s: str, limit: int = TOOL_RESULT_HARD_LIMIT) -> str:
    if len(s) <= limit:
        return s
    return s[: limit - 80] + f"\n... [output truncated, total {len(s)} chars]"


class Agent:
    """Агент text2sql: на вход NL-вопрос, на выход NL-ответ."""

    def __init__(
        self,
        settings: Settings | None = None,
        *,
        oracle: OracleClient | None = None,
        llm: LLMClient | None = None,
        max_turns: int = MAX_TURNS,
        verbose: bool = True,
    ) -> None:
        self.settings = settings or Settings.from_env()
        self.oracle = oracle or OracleClient(self.settings)
        self.llm = llm or LLMClient(self.settings)
        self.max_turns = max_turns
        self.verbose = verbose

    def _log(self, msg: str) -> None:
        if self.verbose:
            print(msg, file=sys.stderr, flush=True)

    def run(self, question: str) -> AgentResult:
        question = (question or "").strip()
        if not question:
            return AgentResult(
                answer="Пустой вопрос — нечего обрабатывать.",
                completed=False,
                error="empty question",
            )

        ctx = ToolContext(oracle=self.oracle)
        try:
            self.oracle.connect()
        except Exception as e:  # noqa: BLE001
            return AgentResult(
                answer=f"Ошибка подключения к Oracle: {e}",
                completed=False,
                error=str(e),
            )

        data_range = self._probe_data_range()
        system_prompt = build_system_prompt(data_range=data_range)
        messages: list[dict[str, Any]] = [
            {"role": "system", "content": system_prompt},
            {"role": "user", "content": question},
        ]

        last_assistant_text = ""

        for turn in range(1, self.max_turns + 1):
            self._log(f"[agent] turn {turn}/{self.max_turns}: calling LLM")
            try:
                resp = self.llm.chat(
                    model=self.settings.sql_model,
                    messages=messages,
                    tools=TOOL_SCHEMAS,
                    tool_choice="auto",
                    temperature=0.0,
                )
            except Exception as e:  # noqa: BLE001
                self._log(f"[agent] LLM error: {e}")
                return AgentResult(
                    answer=f"Ошибка обращения к LLM: {e}",
                    completed=False,
                    error=str(e),
                    turns=turn,
                    tool_calls=[r.__dict__ for r in ctx.history],
                )

            choice = resp.choices[0]
            msg = choice.message
            tool_calls = getattr(msg, "tool_calls", None) or []
            assistant_content = msg.content or ""
            if assistant_content:
                last_assistant_text = assistant_content

            # Добавляем assistant-message (с tool_calls) в историю диалога.
            assistant_msg: dict[str, Any] = {
                "role": "assistant",
                "content": assistant_content,
            }
            if tool_calls:
                assistant_msg["tool_calls"] = [
                    {
                        "id": tc.id,
                        "type": "function",
                        "function": {
                            "name": tc.function.name,
                            "arguments": tc.function.arguments or "{}",
                        },
                    }
                    for tc in tool_calls
                ]
            messages.append(assistant_msg)

            if not tool_calls:
                # Модель не вызвала tool — пробуем подтолкнуть к final_answer.
                self._log("[agent] no tool calls; nudging toward final_answer")
                if any(rec.name == "execute_sql" and rec.error is None for rec in ctx.history):
                    # У нас уже есть какие-то данные — пусть оформит ответ.
                    messages.append(
                        {
                            "role": "user",
                            "content": (
                                "Сформируй итоговый ответ через tool final_answer "
                                "с конкретными цифрами по запросу пользователя."
                            ),
                        }
                    )
                else:
                    messages.append(
                        {
                            "role": "user",
                            "content": (
                                "Ты не вызвал ни одного tool. Чтобы ответить на "
                                "вопрос, обязательно сначала выполни Oracle SQL "
                                "через execute_sql, а затем заверши final_answer."
                            ),
                        }
                    )
                continue

            # Выполняем все tool_calls этого хода.
            for tc in tool_calls:
                name = tc.function.name
                arguments_json = tc.function.arguments or "{}"
                self._log(f"[agent]  tool: {name} args={arguments_json[:200]}")
                tool_output = call_tool(ctx, name, arguments_json)
                tool_output = _truncate(tool_output)
                messages.append(
                    {
                        "role": "tool",
                        "tool_call_id": tc.id,
                        "name": name,
                        "content": tool_output,
                    }
                )

            if ctx.final is not None:
                self._log("[agent] final_answer received — done")
                return AgentResult(
                    answer=ctx.final["text"],
                    supporting_data=ctx.final.get("supporting_data") or {},
                    turns=turn,
                    tool_calls=[
                        {
                            "name": r.name,
                            "arguments": r.arguments,
                            "error": r.error,
                        }
                        for r in ctx.history
                    ],
                    completed=True,
                )

        # Лимит шагов исчерпан — попытаемся достать ответ хоть как-то.
        self._log("[agent] max_turns exceeded — forcing final_answer")
        fallback = self._force_final_answer(messages, ctx, question, last_assistant_text)
        return fallback

    def _force_final_answer(
        self,
        messages: list[dict[str, Any]],
        ctx: ToolContext,
        question: str,
        last_assistant_text: str,
    ) -> AgentResult:
        """Если модель не уложилась в max_turns — последний шанс на ответ."""
        forced_messages = list(messages) + [
            {
                "role": "user",
                "content": (
                    "Лимит шагов почти исчерпан. Сформируй итоговый ответ через "
                    "final_answer прямо сейчас. Если данных не хватило — честно "
                    "укажи это в тексте."
                ),
            }
        ]
        try:
            resp = self.llm.chat(
                model=self.settings.response_model,
                messages=forced_messages,
                tools=TOOL_SCHEMAS,
                tool_choice={
                    "type": "function",
                    "function": {"name": "final_answer"},
                },
                temperature=0.0,
            )
            choice = resp.choices[0]
            tool_calls = getattr(choice.message, "tool_calls", None) or []
            for tc in tool_calls:
                if tc.function.name == "final_answer":
                    try:
                        args = json.loads(tc.function.arguments or "{}")
                    except json.JSONDecodeError:
                        args = {"text": tc.function.arguments or ""}
                    supporting = args.get("supporting_data")
                    if not isinstance(supporting, dict):
                        supporting = {}
                    return AgentResult(
                        answer=str(args.get("text") or last_assistant_text or
                                   "Не удалось получить ответ от LLM."),
                        supporting_data=supporting,
                        turns=self.max_turns,
                        tool_calls=[
                            {"name": r.name, "arguments": r.arguments, "error": r.error}
                            for r in ctx.history
                        ],
                        completed=False,
                    )
        except Exception as e:  # noqa: BLE001
            self._log(f"[agent] forced final_answer failed: {e}")

        return AgentResult(
            answer=last_assistant_text
            or "Не удалось получить ответ от LLM (исчерпан лимит шагов).",
            turns=self.max_turns,
            tool_calls=[
                {"name": r.name, "arguments": r.arguments, "error": r.error}
                for r in ctx.history
            ],
            completed=False,
            error="max_turns exceeded",
        )

    def _probe_data_range(self) -> tuple[str, str] | None:
        """Один short SQL для определения min/max MONTH_DT — закрепляет horizon в prompt."""
        try:
            qr = self.oracle.execute(
                "SELECT MIN(MONTH_DT), MAX(MONTH_DT) FROM client_product",
                max_rows=1,
            )
        except Exception as e:  # noqa: BLE001
            self._log(f"[agent] probe data range failed: {e}")
            return None
        if not qr.rows or len(qr.rows[0]) < 2:
            return None
        min_dt, max_dt = qr.rows[0][0], qr.rows[0][1]
        if min_dt is None or max_dt is None:
            return None
        # _normalize_cell уже превратил даты в строки 'YYYY-MM-DD ...'.
        return (str(min_dt)[:10], str(max_dt)[:10])

    def close(self) -> None:
        try:
            self.oracle.close()
        except Exception:  # noqa: BLE001
            pass

"""Реализация tool-функций, доступных агенту через function calling.

Каждый tool возвращает JSON-сериализуемый dict (или строку для final_answer).
Описание схем параметров — в TOOL_SCHEMAS (формат OpenAI tools).
"""

from __future__ import annotations

import json
from dataclasses import dataclass, field
from typing import Any

from . import schema as schema_mod
from .db import OracleClient, UnsafeSqlError
from .validators import validate


@dataclass
class ToolCallRecord:
    name: str
    arguments: dict[str, Any]
    result: Any
    error: str | None = None


@dataclass
class ToolContext:
    """Состояние одного диалога: подключение к Oracle, история вызовов, finalize."""

    oracle: OracleClient
    max_rows: int = 200
    history: list[ToolCallRecord] = field(default_factory=list)
    final: dict[str, Any] | None = None

    def record(self, rec: ToolCallRecord) -> None:
        self.history.append(rec)


TOOL_SCHEMAS: list[dict[str, Any]] = [
    {
        "type": "function",
        "function": {
            "name": "inspect_schema",
            "description": (
                "Получить полное описание таблицы и её полей (бизнес-семантика, "
                "единицы измерения, правила агрегации, примеры SQL). "
                "Вызывай, если нужно уточнить смысл или единицы измерения колонки."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "table": {
                        "type": "string",
                        "description": "Имя таблицы (по умолчанию client_product).",
                        "default": "client_product",
                    }
                },
                "required": [],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "execute_sql",
            "description": (
                "Выполнить read-only SQL (Oracle 21c, SELECT/WITH) и получить "
                "результат: список колонок и строк. Запрещено любое DML/DDL. "
                "Используй параметры запроса в виде литералов: даты как "
                "DATE '2025-01-31'. Возвращается не более max_rows строк."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "sql": {
                        "type": "string",
                        "description": "Готовый Oracle SQL запрос (SELECT/WITH).",
                    },
                    "max_rows": {
                        "type": "integer",
                        "description": "Лимит строк в ответе (по умолчанию 200).",
                        "default": 200,
                    },
                },
                "required": ["sql"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "validate_result",
            "description": (
                "Прогнать sanity-check для последнего execute_sql: размер, "
                "не-NULL колонки, разумные диапазоны. Возвращает passed/issues."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "expectations": {
                        "type": "object",
                        "description": (
                            "Ожидания: min_rows (int), max_rows (int), "
                            "non_null_columns (list[str]), "
                            "non_negative_columns (list[str]), "
                            "value_ranges (dict col -> [min, max])."
                        ),
                    }
                },
                "required": [],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "final_answer",
            "description": (
                "Сформировать итоговый ответ пользователю на естественном языке "
                "с конкретными цифрами. Вызывается ровно один раз в конце."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "text": {
                        "type": "string",
                        "description": "Итоговый ответ пользователю.",
                    },
                    "supporting_data": {
                        "type": "object",
                        "description": (
                            "Опционально: ключевые цифры/SQL, на которые "
                            "опирается ответ."
                        ),
                    },
                },
                "required": ["text"],
            },
        },
    },
]


def _last_query(ctx: ToolContext):
    for rec in reversed(ctx.history):
        if rec.name == "execute_sql" and isinstance(rec.result, dict) and rec.error is None:
            return rec.result
    return None


def tool_inspect_schema(ctx: ToolContext, args: dict[str, Any]) -> dict[str, Any]:
    table = (args.get("table") or "client_product").strip()
    md = schema_mod.get_table_metadata(table)
    # Передаём только то, что нужно для понимания семантики, без дубликатов.
    fields_compact: dict[str, dict[str, Any]] = {}
    for name, info in md["fields"].items():
        fields_compact[name] = {
            "type": info.get("type"),
            "description": info.get("description"),
            "category": info.get("category"),
            "aggregation_between_clients": info.get("aggregation_between_clients"),
            "aggregation_between_month": info.get("aggregation_between_month"),
            "operation_currency": info.get("operation_currency"),
            "result_currency_equivalent": info.get("result_currency_equivalent"),
            "is_key": info.get("is_key", False),
        }
    return {
        "table": md["table_name"],
        "description": md["description"].strip(),
        "fields": fields_compact,
        "sql_examples": md.get("sql_examples", []),
    }


def tool_execute_sql(ctx: ToolContext, args: dict[str, Any]) -> dict[str, Any]:
    sql = (args.get("sql") or "").strip()
    if not sql:
        return {"error": "пустой SQL"}
    max_rows = int(args.get("max_rows") or ctx.max_rows)
    max_rows = max(1, min(max_rows, 1000))
    try:
        result = ctx.oracle.execute(sql, max_rows=max_rows)
    except UnsafeSqlError as e:
        return {"error": f"UnsafeSqlError: {e}", "sql": sql}
    except Exception as e:  # noqa: BLE001
        # Пытаемся вернуть аккуратное сообщение об ошибке Oracle.
        return {"error": f"{type(e).__name__}: {e}", "sql": sql}
    return result.as_dict()


def tool_validate_result(ctx: ToolContext, args: dict[str, Any]) -> dict[str, Any]:
    last = _last_query(ctx)
    if last is None:
        return {
            "passed": False,
            "issues": ["нет ни одного успешного execute_sql для валидации"],
            "warnings": [],
        }
    # Восстанавливаем QueryResult в облегчённой форме.
    from .db import QueryResult

    qr = QueryResult(
        columns=list(last.get("columns") or []),
        rows=list(last.get("rows") or []),
        row_count=int(last.get("row_count") or 0),
        truncated=bool(last.get("truncated") or False),
        error=last.get("error"),
        sql=str(last.get("sql") or ""),
    )
    expectations = args.get("expectations") or {}
    return validate(qr, expectations)


def tool_final_answer(ctx: ToolContext, args: dict[str, Any]) -> dict[str, Any]:
    text = (args.get("text") or "").strip()
    if not text:
        return {"ok": False, "error": "text пустой"}
    supporting = args.get("supporting_data") or {}
    ctx.final = {"text": text, "supporting_data": supporting}
    return {"ok": True}


TOOL_DISPATCH = {
    "inspect_schema": tool_inspect_schema,
    "execute_sql": tool_execute_sql,
    "validate_result": tool_validate_result,
    "final_answer": tool_final_answer,
}


def call_tool(ctx: ToolContext, name: str, arguments_json: str) -> str:
    """Вызвать tool по имени, аргументы — JSON-строка от модели."""
    try:
        arguments = json.loads(arguments_json) if arguments_json else {}
        if not isinstance(arguments, dict):
            arguments = {"value": arguments}
    except json.JSONDecodeError as e:
        rec = ToolCallRecord(
            name=name,
            arguments={"raw": arguments_json},
            result=None,
            error=f"Невалидный JSON в аргументах: {e}",
        )
        ctx.record(rec)
        return json.dumps({"error": rec.error}, ensure_ascii=False)

    handler = TOOL_DISPATCH.get(name)
    if handler is None:
        rec = ToolCallRecord(
            name=name,
            arguments=arguments,
            result=None,
            error=f"Неизвестный tool: {name}",
        )
        ctx.record(rec)
        return json.dumps({"error": rec.error}, ensure_ascii=False)

    try:
        result = handler(ctx, arguments)
    except Exception as e:  # noqa: BLE001
        rec = ToolCallRecord(
            name=name,
            arguments=arguments,
            result=None,
            error=f"{type(e).__name__}: {e}",
        )
        ctx.record(rec)
        return json.dumps({"error": rec.error}, ensure_ascii=False)

    ctx.record(ToolCallRecord(name=name, arguments=arguments, result=result))
    return json.dumps(result, ensure_ascii=False, default=str)

"""Доступ к Oracle XE: соединение + безопасное выполнение SELECT-запросов."""

from __future__ import annotations

import datetime as _dt
import decimal
import re
from dataclasses import dataclass, field
from typing import Any, Iterable

import oracledb

from .config import Settings

# Максимум строк, которые мы возвращаем модели (защита от случайных SELECT *).
DEFAULT_MAX_ROWS = 200

# Грубая проверка read-only: разрешаем только SELECT / WITH.
_ALLOWED_LEADING = re.compile(r"^\s*(SELECT|WITH)\b", re.IGNORECASE)
_FORBIDDEN_PAT = re.compile(
    r"\b(INSERT|UPDATE|DELETE|MERGE|TRUNCATE|DROP|ALTER|CREATE|GRANT|REVOKE|"
    r"COMMIT|ROLLBACK|SAVEPOINT|EXECUTE|CALL|BEGIN|DECLARE)\b",
    re.IGNORECASE,
)


class UnsafeSqlError(ValueError):
    """SQL содержит запрещённую (не read-only) операцию."""


@dataclass
class QueryResult:
    columns: list[str]
    rows: list[list[Any]]
    row_count: int
    truncated: bool = False
    error: str | None = None
    sql: str = ""

    def as_dict(self) -> dict[str, Any]:
        return {
            "columns": self.columns,
            "rows": self.rows,
            "row_count": self.row_count,
            "truncated": self.truncated,
            "error": self.error,
            "sql": self.sql,
        }


def assert_read_only(sql: str) -> None:
    """Грубая защита: пропускаем только SELECT/WITH без DDL/DML."""
    stripped = sql.strip().rstrip(";").strip()
    if not _ALLOWED_LEADING.match(stripped):
        raise UnsafeSqlError(
            "Разрешены только SELECT/WITH запросы (read-only режим)."
        )
    if _FORBIDDEN_PAT.search(stripped):
        raise UnsafeSqlError(
            "SQL содержит DDL/DML операцию — запрос отклонён."
        )
    # Не допускаем нескольких statement'ов.
    inner = stripped
    if ";" in inner:
        # Точка с запятой допустима только в самом конце (мы её уже срезали).
        raise UnsafeSqlError("Несколько SQL statement'ов в одном вызове запрещено.")


def _normalize_cell(value: Any) -> Any:
    """Делаем значения сериализуемыми в JSON."""
    if isinstance(value, _dt.datetime):
        return value.strftime("%Y-%m-%d %H:%M:%S")
    if isinstance(value, _dt.date):
        return value.strftime("%Y-%m-%d")
    if isinstance(value, decimal.Decimal):
        # Decimal → int если целое, иначе float.
        if value == value.to_integral_value():
            try:
                return int(value)
            except (OverflowError, ValueError):
                return float(value)
        return float(value)
    if isinstance(value, oracledb.LOB):
        try:
            return value.read()
        except Exception:  # noqa: BLE001
            return str(value)
    return value


@dataclass
class OracleClient:
    settings: Settings
    _conn: oracledb.Connection | None = field(default=None, repr=False)

    def connect(self) -> oracledb.Connection:
        if self._conn is None:
            self._conn = oracledb.connect(
                user=self.settings.oracle_user,
                password=self.settings.oracle_password,
                dsn=self.settings.oracle_dsn,
            )
        return self._conn

    def close(self) -> None:
        if self._conn is not None:
            try:
                self._conn.close()
            finally:
                self._conn = None

    def __enter__(self) -> "OracleClient":
        self.connect()
        return self

    def __exit__(self, exc_type, exc, tb) -> None:
        self.close()

    def execute(self, sql: str, max_rows: int = DEFAULT_MAX_ROWS) -> QueryResult:
        """Выполнить SELECT/WITH; вернуть нормализованные строки + метаинфо."""
        assert_read_only(sql)
        conn = self.connect()
        cur = conn.cursor()
        try:
            cur.execute(sql.rstrip(";").strip())
            columns: list[str] = [str(d[0]) for d in (cur.description or [])]
            raw_rows: Iterable[tuple[Any, ...]] = cur.fetchmany(max_rows + 1)
            rows = [[_normalize_cell(v) for v in r] for r in raw_rows]
            truncated = len(rows) > max_rows
            if truncated:
                rows = rows[:max_rows]
            return QueryResult(
                columns=columns,
                rows=rows,
                row_count=len(rows),
                truncated=truncated,
                sql=sql,
            )
        finally:
            cur.close()

"""Тонкая обёртка над OpenAI-совместимым клиентом (Ollama)."""

from __future__ import annotations

from dataclasses import dataclass
from typing import Any

from openai import OpenAI

from .config import Settings


@dataclass
class LLMClient:
    settings: Settings
    _client: OpenAI | None = None

    def client(self) -> OpenAI:
        if self._client is None:
            self._client = OpenAI(
                api_key=self.settings.api_key,
                base_url=self.settings.api_url,
                timeout=180.0,
                max_retries=1,
            )
        return self._client

    def chat(
        self,
        *,
        model: str,
        messages: list[dict[str, Any]],
        tools: list[dict[str, Any]] | None = None,
        tool_choice: str | dict[str, Any] | None = None,
        temperature: float = 0.0,
        response_format: dict[str, Any] | None = None,
    ) -> Any:
        kwargs: dict[str, Any] = {
