"""Sanity-checks для результата SQL запроса."""

from __future__ import annotations

from typing import Any

from .db import QueryResult


def _coerce_number(x: Any) -> float | None:
    if x is None:
        return None
    if isinstance(x, bool):
        return float(x)
    if isinstance(x, (int, float)):
        return float(x)
    try:
        return float(str(x).replace(",", "."))
    except (TypeError, ValueError):
        return None


def validate(result: QueryResult, expectations: dict[str, Any] | None) -> dict[str, Any]:
    """Прогоняем сanity-check.

    Возможные ключи expectations:
        min_rows (int): минимально допустимое число строк
        max_rows (int): максимально допустимое число строк
        non_null_columns (list[str]): эти колонки не должны быть полностью NULL
        value_ranges (dict[str, [min, max]]): диапазон для числовой колонки
        non_negative_columns (list[str]): значения должны быть >= 0
        description (str): свободный текст-цель проверки (для логов)
    """
    expectations = expectations or {}
    issues: list[str] = []
    warnings: list[str] = []
    col_index = {name: i for i, name in enumerate(result.columns)}

    if result.error:
        issues.append(f"SQL error: {result.error}")

    min_rows = expectations.get("min_rows")
    if isinstance(min_rows, int) and result.row_count < min_rows:
        issues.append(f"строк {result.row_count}, ожидалось не меньше {min_rows}")
    max_rows = expectations.get("max_rows")
    if isinstance(max_rows, int) and result.row_count > max_rows:
        issues.append(f"строк {result.row_count}, ожидалось не больше {max_rows}")

    if result.row_count == 0:
        warnings.append("Результат пуст — проверь фильтры (даты/сегменты/имена).")

    non_null_cols = expectations.get("non_null_columns") or []
    for col in non_null_cols:
        if col not in col_index:
            warnings.append(f"колонка {col} отсутствует в результате")
            continue
        idx = col_index[col]
        if result.row_count and all(r[idx] is None for r in result.rows):
            issues.append(f"колонка {col} полностью NULL")

    ranges = expectations.get("value_ranges") or {}
    for col, bounds in ranges.items():
        if col not in col_index:
            warnings.append(f"колонка {col} отсутствует в результате")
            continue
        if not (isinstance(bounds, (list, tuple)) and len(bounds) == 2):
            warnings.append(f"некорректный диапазон для {col}: {bounds}")
            continue
        lo, hi = bounds
        idx = col_index[col]
        for ri, row in enumerate(result.rows):
            v = _coerce_number(row[idx])
            if v is None:
                continue
            if lo is not None and v < lo:
                issues.append(
                    f"{col}[row {ri}]={v} меньше нижней границы {lo}"
                )
                break
            if hi is not None and v > hi:
                issues.append(
                    f"{col}[row {ri}]={v} больше верхней границы {hi}"
                )
                break

    non_neg = expectations.get("non_negative_columns") or []
    for col in non_neg:
        if col not in col_index:
            warnings.append(f"колонка {col} отсутствует в результате")
            continue
        idx = col_index[col]
        for ri, row in enumerate(result.rows):
            v = _coerce_number(row[idx])
            if v is not None and v < 0:
                issues.append(f"{col}[row {ri}]={v} отрицательное")
                break

    return {
        "passed": not issues,
        "issues": issues,
        "warnings": warnings,
        "row_count": result.row_count,
        "truncated": result.truncated,
        "columns": result.columns,
    }

